import React, { ReactNode } from "react";

import { EyeIcon, Icon, SlidersIcon } from "@steez-ui/icons";
import type { SteezIconName } from "@steez-ui/icons";

import styles from "./PageHeader.module.css";

export interface PageHeaderProps {
  title: string;
  description?: string;
  icon?: SteezIconName;
  extra?: ReactNode;
  className?: string;
  brand?: ReactNode;
  onBrandClick?: () => void;
  brandTitle?: string;
  brandAriaLabel?: string;
  onBack?: () => void;
  onSettings?: () => void;
  onViewerToggle?: () => void;
  viewerVisible?: boolean;
  viewerShowLabel?: string;
  viewerHideLabel?: string;
}

export function PageHeader({
  title,
  description,
  icon,
  extra,
  className = "",
  brand,
  onBrandClick,
  brandTitle,
  brandAriaLabel,
  onBack,
  onSettings,
  onViewerToggle,
  viewerVisible,
  viewerShowLabel = "Show viewer",
  viewerHideLabel = "Hide viewer",
}: PageHeaderProps) {
  const viewerLabel = viewerVisible ? viewerHideLabel : viewerShowLabel;

  return (
    <div className={`${styles.header} ${className}`.trim()}>
      <div className={styles.headerRow}>
        <div className={styles.brandCluster}>
          {brand || onBrandClick ? (
            <button
              type="button"
              className={styles.brandButton}
              onClick={onBrandClick}
              title={brandTitle}
              aria-label={brandAriaLabel}
            >
              <span className={styles.brandVisual}>{brand ?? title.slice(0, 1)}</span>
            </button>
          ) : null}
          <div className={styles.headerContent}>
            <h2>
              {icon ? (
                <span className={styles.titleIcon}>
                  <Icon icon={icon} width={18} height={18} />
                </span>
              ) : null}
              {title}
            </h2>
            {description ? <p>{description}</p> : null}
          </div>
        </div>
        <div className={styles.headerExtra}>
          {extra}
          {onBack ? (
            <button type="button" className={styles.iconButton} onClick={onBack} aria-label="Go back">
              <Icon icon="chevronLeft" width={18} height={18} />
            </button>
          ) : null}
          {onSettings ? (
            <button type="button" className={styles.iconButton} onClick={onSettings} aria-label="Open settings">
              <SlidersIcon width={18} height={18} />
            </button>
          ) : null}
          {onViewerToggle ? (
            <button
              type="button"
              className={styles.iconButton}
              onClick={onViewerToggle}
              aria-label={viewerLabel}
              title={viewerLabel}
            >
              <EyeIcon width={18} height={18} />
            </button>
          ) : null}
        </div>
      </div>
    </div>
  );
}

.header {
  padding: 16px 24px;
  background: var(--bg-secondary);
}

.headerRow {
  display: flex;
  align-items: center;
  gap: 12px;
}

.brandCluster {
  display: flex;
  align-items: center;
  gap: 12px;
}

.brandButton {
  border: none;
  background: transparent;
  padding: 0;
  margin: 0;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
}

.brandButton:focus-visible {
  outline: 2px solid var(--color-border-hover);
  outline-offset: 2px;
  border-radius: 6px;
}

.brandVisual {
  height: 48px;
  width: 48px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: 1px solid var(--color-border-default);
  border-radius: 6px;
  color: var(--text-primary);
  background: color-mix(in srgb, var(--bg-primary) 90%, transparent);
}

.headerContent {
  line-height: normal;
}

.headerContent h2 {
  margin: 0;
  font-size: 32px;
  font-weight: 400;
  font-family: var(--font-display);
  letter-spacing: 0.03em;
  color: var(--color-text-primary);
}

.titleIcon {
  display: inline-flex;
  margin-right: 8px;
  vertical-align: middle;
}

.headerContent p {
  margin: 0;
  font-size: 14px;
  color: var(--color-text-secondary);
}

.headerExtra {
  margin-left: auto;
  display: flex;
  align-items: center;
  gap: 8px;
}

.iconButton {
  border: none;
  background: transparent;
  padding: 8px;
  margin: 0;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  color: var(--color-text-secondary);
  transition: color var(--transition-fast);
}

.iconButton:hover {
  color: var(--color-text-primary);
}

.iconButton:focus-visible {
  outline: 2px solid var(--color-border-hover);
  outline-offset: 2px;
  border-radius: 4px;
}

@media (max-width: 767px) {
  .header {
    padding: 12px 16px;
  }

  .brandVisual {
    height: 32px;
    width: 32px;
  }

  .headerContent h2 {
    font-size: 22px;
  }

  .headerContent p {
    display: none;
  }
}
